mapper.select:
/** CmmtProgramDao.selectList */ select
,(select string_agg(ROLE_ID, ',') from cmmt_program_role where PROGRAM_ID = a.program_id) as role_ids from cmmt_program a where 1=1 and system_id = #{systemId}
and program_nm like '%' || #{programNm} || '%'
and url_pattern like '%' || #{urlPattern} || '%'

/** CmmtProgramDao.selectByName */
select

    ,(select string_agg(ROLE_ID, ',') from cmmt_program_role where PROGRAM_ID = a.program_id) as role_ids
from
    cmmt_program a
where
	system_id = #{systemId}
	and program_nm = #{programNm}

/** CmmtProgramDao.selectByUrlPattern */
select

    ,(select string_agg(ROLE_ID, ',') from cmmt_program_role where PROGRAM_ID = a.program_id) as role_ids
from
    cmmt_program a
where
	system_id = #{systemId}
	and http_method = #{httpMethod}
	and url_pattern = #{urlPattern}

mapper.update:
/** CmmtProgramDao.incCheckOrder */
update cmmt_program set
	check_order = check_order + 1
where
	check_order >= #{checkOrder}

/** CmmtProgramDao.update */
update cmmt_program set
	program_nm   = #{programNm}
	,system_id	 = #{systemId}
	,http_method = #{httpMethod}
	,url_pattern = #{urlPattern}
	,check_order = #{checkOrder}
	,creator_id  = #{creatorId}
	,created_dt  = #{createdDt}
	,updater_id  = #{updaterId}
	,updated_dt  = #{updatedDt}
where
	program_id = #{programId}

mapper.delete:
/** CmmtProgramRoleDao.deleteList */
delete from
	cmmt_program
where
	program_id = #{programId}
